import { ipcMain } from 'electron';
import {
  IPC_CHANNELS,
  MigrationStartSchema,
  MigrationGetSessionSchema,
  MigrationGetItemsSchema,
  MigrationSelectItemsSchema,
  MigrationExecuteSchema,
  MigrationVerifySchema,
  MigrationRollbackSchema,
  MigrationGetDecommissionPlanSchema,
  MigrationExecuteDecommissionStepSchema,
  MigrationGetCutoverPlanSchema,
  MigrationExecuteCutoverSchema,
  MigrationCancelSchema,
  MigrationGetHistorySchema,
  MigrationRetryItemSchema,
} from './types';
import type { ApiResult } from './types';
import { migrationEngine } from '../services/migration/MigrationEngine';

export function registerMigrationHandlers() {
  ipcMain.handle(
    IPC_CHANNELS.MIGRATION_START,
    async (_event, input): Promise<ApiResult> => {
      try {
        const validated = MigrationStartSchema.parse(input);
        const result = await migrationEngine.startMigration(validated);
        return { success: true, data: result };
      } catch (error) {
        console.error('[Migration] Start failed:', error);
        return { success: false, error: error instanceof Error ? error.message : String(error) };
      }
    }
  );

  ipcMain.handle(
    IPC_CHANNELS.MIGRATION_GET_SESSION,
    async (_event, input): Promise<ApiResult> => {
      try {
        const { migrationId } = MigrationGetSessionSchema.parse(input);
        const session = migrationEngine.getMigration(migrationId);
        return { success: true, data: session };
      } catch (error) {
        console.error('[Migration] Get session failed:', error);
        return { success: false, error: error instanceof Error ? error.message : String(error) };
      }
    }
  );

  ipcMain.handle(
    IPC_CHANNELS.MIGRATION_GET_ITEMS,
    async (_event, input): Promise<ApiResult> => {
      try {
        const { migrationId } = MigrationGetItemsSchema.parse(input);
        const items = migrationEngine.getDiscoveredItems(migrationId);
        return { success: true, data: items };
      } catch (error) {
        console.error('[Migration] Get items failed:', error);
        return { success: false, error: error instanceof Error ? error.message : String(error) };
      }
    }
  );

  ipcMain.handle(
    IPC_CHANNELS.MIGRATION_SELECT_ITEMS,
    async (_event, input): Promise<ApiResult> => {
      try {
        const { selection } = MigrationSelectItemsSchema.parse(input);
        for (const [itemId, selected] of Object.entries(selection)) {
          migrationEngine.updateItemSelection(itemId, selected);
        }
        return { success: true, data: null };
      } catch (error) {
        console.error('[Migration] Select items failed:', error);
        return { success: false, error: error instanceof Error ? error.message : String(error) };
      }
    }
  );

  ipcMain.handle(
    IPC_CHANNELS.MIGRATION_EXECUTE,
    async (_event, input): Promise<ApiResult> => {
      try {
        const validated = MigrationExecuteSchema.parse(input);
        // prepareMigration is synchronous: updates DB selections/status then
        // kicks off the async import in the background. Returns immediately
        // so the frontend can mount its progress listener before events fire.
        migrationEngine.prepareMigration(validated);
        return { success: true, data: null };
      } catch (error) {
        console.error('[Migration] Execute failed:', error);
        return { success: false, error: error instanceof Error ? error.message : String(error) };
      }
    }
  );

  ipcMain.handle(
    IPC_CHANNELS.MIGRATION_VERIFY,
    async (_event, input): Promise<ApiResult> => {
      try {
        const { migrationId } = MigrationVerifySchema.parse(input);
        // prepareVerification is synchronous: updates DB timestamps then
        // kicks off the async verification in the background. Returns immediately
        // so the frontend receives progress events in real-time.
        migrationEngine.prepareVerification(migrationId);
        return { success: true, data: null };
      } catch (error) {
        console.error('[Migration] Verify failed:', error);
        return { success: false, error: error instanceof Error ? error.message : String(error) };
      }
    }
  );

  ipcMain.handle(
    IPC_CHANNELS.MIGRATION_ROLLBACK,
    async (_event, input): Promise<ApiResult> => {
      try {
        const { migrationId } = MigrationRollbackSchema.parse(input);
        await migrationEngine.rollback(migrationId);
        return { success: true, data: null };
      } catch (error) {
        console.error('[Migration] Rollback failed:', error);
        return { success: false, error: error instanceof Error ? error.message : String(error) };
      }
    }
  );

  ipcMain.handle(
    IPC_CHANNELS.MIGRATION_GET_DECOMMISSION_PLAN,
    async (_event, input): Promise<ApiResult> => {
      try {
        const { migrationId } = MigrationGetDecommissionPlanSchema.parse(input);
        const plan = await migrationEngine.getDecommissionPlan(migrationId);
        return { success: true, data: plan };
      } catch (error) {
        console.error('[Migration] Get decommission plan failed:', error);
        return { success: false, error: error instanceof Error ? error.message : String(error) };
      }
    }
  );

  ipcMain.handle(
    IPC_CHANNELS.MIGRATION_EXECUTE_DECOMMISSION_STEP,
    async (_event, input): Promise<ApiResult> => {
      try {
        const { migrationId, stepId } = MigrationExecuteDecommissionStepSchema.parse(input);
        const result = await migrationEngine.executeDecommissionStep(migrationId, stepId);
        return { success: true, data: result };
      } catch (error) {
        console.error('[Migration] Execute decommission step failed:', error);
        return { success: false, error: error instanceof Error ? error.message : String(error) };
      }
    }
  );

  ipcMain.handle(
    IPC_CHANNELS.MIGRATION_GET_CUTOVER_PLAN,
    async (_event, input): Promise<ApiResult> => {
      try {
        const { migrationId } = MigrationGetCutoverPlanSchema.parse(input);
        const plan = await migrationEngine.getCutoverPlan(migrationId);
        return { success: true, data: plan };
      } catch (error) {
        console.error('[Migration] Get cutover plan failed:', error);
        return { success: false, error: error instanceof Error ? error.message : String(error) };
      }
    }
  );

  ipcMain.handle(
    IPC_CHANNELS.MIGRATION_EXECUTE_CUTOVER,
    async (_event, input): Promise<ApiResult> => {
      try {
        const { migrationId } = MigrationExecuteCutoverSchema.parse(input);
        await migrationEngine.executeCutover(migrationId);
        return { success: true, data: null };
      } catch (error) {
        console.error('[Migration] Execute cutover failed:', error);
        return { success: false, error: error instanceof Error ? error.message : String(error) };
      }
    }
  );

  ipcMain.handle(
    IPC_CHANNELS.MIGRATION_CANCEL,
    async (_event, input): Promise<ApiResult> => {
      try {
        const { migrationId } = MigrationCancelSchema.parse(input);
        migrationEngine.cancelMigration(migrationId);
        return { success: true, data: null };
      } catch (error) {
        console.error('[Migration] Cancel failed:', error);
        return { success: false, error: error instanceof Error ? error.message : String(error) };
      }
    }
  );

  ipcMain.handle(
    IPC_CHANNELS.MIGRATION_GET_HISTORY,
    async (_event, input): Promise<ApiResult> => {
      try {
        const { serverId } = MigrationGetHistorySchema.parse(input);
        const history = migrationEngine.getMigrationsForServer(serverId);
        return { success: true, data: history };
      } catch (error) {
        console.error('[Migration] Get history failed:', error);
        return { success: false, error: error instanceof Error ? error.message : String(error) };
      }
    }
  );

  ipcMain.handle(
    IPC_CHANNELS.MIGRATION_RETRY_ITEM,
    async (_event, input): Promise<ApiResult> => {
      try {
        const { itemId } = MigrationRetryItemSchema.parse(input);
        migrationEngine.retryItem(itemId);
        return { success: true, data: null };
      } catch (error) {
        console.error('[Migration] Retry item failed:', error);
        return { success: false, error: error instanceof Error ? error.message : String(error) };
      }
    }
  );
}
